export function useAuth() {
  const {
    session,
    setAuthToken,
    getAuthToken,
    removeAuthToken,
    setRefreshToken,
    getRefreshToken,
    removeRefreshToken,
    setSession,
    getSession,
    clearSession,
    isSessionValid,
    clearAllData,
  } = useDataManager();

  const login = useCallback(
    async ({ authToken, refreshToken, sessionData, profile }) => {
      const promises = [];
      if (authToken) promises.push(setAuthToken(authToken));
      if (refreshToken) promises.push(setRefreshToken(refreshToken));
      if (sessionData) promises.push(setSession(sessionData));
      await Promise.all(promises);

      // Profile is set separately to leverage the split logic
      if (profile) {
        const { setUserProfile } = useDataManager();
        // This won't work inside useCallback referencing another hook.
        // Instead, accept setUserProfile as a dependency.
      }
    },
    [setAuthToken, setRefreshToken, setSession]
  );

  const logout = useCallback(async () => {
    await clearAllData();
  }, [clearAllData]);

  return {
    session,
    setAuthToken,
    getAuthToken,
    removeAuthToken,
    setRefreshToken,
    getRefreshToken,
    removeRefreshToken,
    setSession,
    getSession,
    clearSession,
    isSessionValid,
    logout,
  };
}

// --- Standalone login helper (use within components) ---

export function useLogin() {
  const {
    setAuthToken,
    setRefreshToken,
    setSession,
    setUserProfile,
  } = useDataManager();

  const login = useCallback(
    async ({ authToken, refreshToken, sessionData, profile }) => {
      const promises = [];
      if (authToken) promises.push(setAuthToken(authToken));
      if (refreshToken) promises.push(setRefreshToken(refreshToken));
      if (sessionData) promises.push(setSession(sessionData));
      if (profile) promises.push(setUserProfile(profile));
      await Promise.all(promises);
    },
    [setAuthToken, setRefreshToken, setSession, setUserProfile]
  );

  return login;
}

